oxy_webhelp_navlinks = {"roles_and_permissions-d30753e9519":{"topics":[{"title":"Roles","shortdesc":"<p class=\"shortdesc\">Roles define privileges for user accounts in a Rubrik cluster. With the administrator         account, you can assign roles that grant different access permissions to user accounts for         specific purposes.<\/p>","href":"saas\/common\/rsc_roles.html","attributes":{"data-id":"rsc_roles"},"menu":{"hasChildren":false},"tocID":"rsc_roles-d30753e9530","topics":[]},{"title":"Creating a role","shortdesc":"<p class=\"shortdesc\">Create a role by defining a custom set of user permissions or start by using a role         template with a set of preselected permissions that you can edit for your use         case.<\/p>","href":"saas\/common\/creating_role.html","attributes":{"data-id":"creating_role"},"menu":{"hasChildren":false},"tocID":"creating_role-d30753e9541","topics":[]},{"title":"Cloning a role","shortdesc":"<p class=\"shortdesc\">Clone an existing role to copy its permissions and settings as a new         role.<\/p>","href":"saas\/common\/cloning_roles.html","attributes":{"data-id":"cloning_roles"},"menu":{"hasChildren":false},"tocID":"cloning_roles-d30753e9552","topics":[]},{"title":"Editing a role","shortdesc":"<p class=\"shortdesc\">Add additional permissions to a role or remove particular permissions from a         role.<\/p>","href":"saas\/common\/editing_a_role.html","attributes":{"data-id":"editing_a_role"},"menu":{"hasChildren":false},"tocID":"editing_a_role-d30753e9563","topics":[]},{"title":"Deleting a role","shortdesc":"<p class=\"shortdesc\">Delete a role to remove a defined set of user permissions.<\/p>","href":"saas\/common\/deleting_a_role.html","attributes":{"data-id":"deleting_a_role"},"menu":{"hasChildren":false},"tocID":"deleting_a_role-d30753e9574","topics":[]},{"title":"Editing role assignments for a single user, SSO group, or service account","shortdesc":"<p class=\"shortdesc\">Edit the roles that are assigned to a single user, SSO group, or service account to         modify the privileges associated with the object.<\/p>","href":"saas\/common\/editing_role_asmt_single_obj.html","attributes":{"data-id":"editing_role_asmt_single_obj"},"menu":{"hasChildren":false},"tocID":"editing_role_asmt_single_obj-d30753e9585","topics":[]},{"title":"Editing role assignments for multiple users, SSO groups, or service accounts","shortdesc":"<p class=\"shortdesc\">Change the roles that are assigned to multiple users, SSO groups, or service accounts         to modify the privileges associated with the objects.<\/p>","href":"saas\/common\/editing_role_asmt_multiple_obj.html","attributes":{"data-id":"editing_role_asmt_multiple_obj"},"menu":{"hasChildren":false},"tocID":"editing_role_asmt_multiple_obj-d30753e9596","topics":[]}]}};